solution_code:
#include <iostream>

int score { 99 };

int main()
{
    int score { 10 };

    {
        int score { 50 };
        std::cout << score << '\n';  // 50
    }

    std::cout << score << '\n';     // 10
    std::cout << ::score << '\n';   // 99

    return 0;
}

